#include<iostream>
#include<cmath>
using namespace std;
int main()
{
	int n,max=0,min=1001,a[101];
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>a[i];
	}
	for(int i=0;i<n;i++){
		if(a[i]<min){
			min=a[i];
		}
		if(a[i]>max){
			max=a[i];
		}
	}
	cout<<max-min;
    return 0;
}
